from unittest.mock import patch

from django.conf import settings
from django.test import TestCase
from django.utils.numberformat import format as nformat

class NumberFormatTests(TestCase):
    def setUp(self):
        self.default_settings = {
            'USE_L10N': False,
            'USE_THOUSAND_SEPARATOR': False,
        }
        self.patch_settings = patch('django.conf.settings', **self.default_settings)
        self.patch_settings.start()

    def tearDown(self):
        self.patch_settings.stop()

    def test_basic_number_formatting(self):
        result = nformat(1234.56, ".", None, 0, "", False, None)
        self.assertEqual(result, "1234.56")

    def test_integer_input(self):
        result = nformat(1234, ".", None, 0, "", False, None)
        self.assertEqual(result, "1234")

    def test_decimal_position_truncation(self):
        result = nformat(1234.5678, ".", 2, 0, "", False, None)
        self.assertEqual(result, "1234.56")

    def test_decimal_position_padding(self):
        result = nformat(1234, ".", 3, 0, "", False, None)
        self.assertEqual(result, "1234.000")

    def test_uniform_grouping(self):
        result = nformat(1234567, ".", None, 3, ",", True, None)
        self.assertEqual(result, "1,234,567")

    def test_non_uniform_grouping(self):
        result = nformat(123456789, ".", None, (3, 2, 0), ",", True, None)
        self.assertEqual(result, "12,34,56,789")

    def test_none_input(self):
        result = nformat(None, ".", None, 0, "", False, None)
        self.assertIsNone(result)

    def test_empty_string_input(self):
        result = nformat("", ".", None, 0, "", False, None)
        self.assertEqual(result, "")

    def test_very_small_decimal(self):
        result = nformat(Decimal("0.0001"), ".", 2, 0, "", False, None)
        self.assertEqual(result, "0.00")

    def test_very_large_number_scientific_notation(self):
        result = nformat(Decimal("1e200"), ".", None, 0, "", False, None)
        self.assertIn("e", result)

    def test_very_small_number_scientific_notation(self):
        result = nformat(Decimal("1e-200"), ".", None, 0, "", False, None)
        self.assertIn("e", result)

    def test_use_l10n_with_settings(self):
        with patch('django.conf.settings', USE_L10N=True, USE_THOUSAND_SEPARATOR=True):
            result = nformat(1234.56, ".", None, 0, "", False, True)
            self.assertEqual(result, "1234.56")

    def test_negative_number(self):
        result = nformat(-1234.56, ".", None, 0, "", False, None)
        self.assertEqual(result, "-1234.56")

    def test_very_large_float_converted_to_decimal(self):
        result = nformat(1e300, ".", None, 0, "", False, None)
        self.assertIn("e", result)
